select
  s.id, 'board', NULL, 'อาจารย์แพทย์อธิบายเรื่อง pharmacokinetics ของยาในงานวิจัย ED ให้ resident ฟัง: ยา A มี volume of distribution (Vd) สูงมาก = 12 L/kg และ protein binding 30% ในขณะที่ยา B มี Vd = 0.2 L/kg และ protein binding 95%

คำถาม: หากผู้ป่วยได้รับ overdose ทั้งสองตัว ตัวใดจะถูกขจัดด้วย hemodialysis ได้ดีกว่า และเพราะอะไร', '[{"label":"A","text":"ยา A เพราะ Vd สูง"},{"label":"B","text":"ยา B เพราะ Vd ต่ำ + protein binding สูง"},{"label":"C","text":"ยา B เพราะ Vd ต่ำ — drug อยู่ใน plasma มาก dialyzer เข้าถึงได้ง่าย ส่วน protein binding สูงเป็นข้อจำกัด แต่ Vd มี impact มากกว่า"},{"label":"D","text":"ทั้งสองตัวขจัดได้พอ ๆ กัน เพราะ HD ไม่ขึ้นกับ pharmacokinetics"},{"label":"E","text":"ยา A เพราะ protein binding ต่ำ ทำให้ free drug ขจัดได้ง่ายแม้ Vd สูง"}]'::jsonb,
  'C', 'หลักการขจัดยาด้วย hemodialysis (EXTRIP criteria): (1) Molecular weight ต่ำ (< 500 Da เก่า, < 25,000 Da hi-flux) (2) Vd ต่ำ (< 1 L/kg) — เพราะถ้า Vd สูง drug กระจายไป tissue ส่วน plasma มีน้อย dialyzer เข้าถึงไม่ได้ (3) Protein binding ต่ำ (< 80%) — เพราะ HD ขจัดเฉพาะ free drug ยา B มี Vd = 0.2 L/kg (ต่ำมาก, drug ส่วนใหญ่อยู่ใน plasma) แต่ protein binding 95% (สูงมาก) — overall ยังถือว่า dialyzable ดีกว่ายา A ที่ Vd 12 L/kg (drug กระจายไป tissue เป็นหลัก ไม่ว่า protein binding เท่าใด HD ก็เอาออกได้น้อย) — ตัวเลือก C อธิบายครบถ้วน. A ผิดเพราะ Vd สูง = ไม่ dialyzable. B ขาดเหตุผล (correct call แต่ no rationale). D ผิดเชิงพื้นฐาน. E ผิดเพราะ Vd สูงเอาชนะ protein binding ต่ำ', NULL,
  'hard', 'toxicology', 'review',
  'emergency_medicine', 'basic_science', 'toxicology', 'adult',
  'EXTRIP Workgroup recommendations (KDIGO 2014); Goodman & Gilman''s Pharmacological Basis 14th ed., Ch. 4', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'em_basic_science'
  and s.audience = 'board'
  and not exists (
    select 1 from public.mcq_questions q
    where q.exam_source = 'AI-generated-board-seed'
      and q.board_specialty = 'emergency_medicine'
      and q.scenario = 'อาจารย์แพทย์อธิบายเรื่อง pharmacokinetics ของยาในงานวิจัย ED ให้ resident ฟัง: ยา A มี volume of distribution (Vd) สูงมาก = 12 L/kg และ protein binding 30% ในขณะที่ยา B มี Vd = 0.2 L/kg และ protein binding 95%

คำถาม: หากผู้ป่วยได้รับ overdose ทั้งสองตัว ตัวใดจะถูกขจัดด้วย hemodialysis ได้ดีกว่า และเพราะอะไร'
  );

insert into public.mcq_questions (
  subject_id, audience, exam_type, scenario, choices, correct_answer,
  explanation, detailed_explanation, difficulty, topic, status,
