  s.id, 'board', NULL, 'ผู้ป่วยอายุ 55 ปี ตรวจสุขภาพประจำปี — BP 145/92 average ของ 3 ครั้ง 4-6 สัปดาห์ห่างกัน + BMI 28 + เคยสูบบุหรี่ + ลดน้ำหนักแล้ว 5kg + cholesterol 218

ก่อนหน้านี้ no medications, no other comorbidity', '[{"label":"A","text":"Ignore"},{"label":"B","text":"Hypertension Management (AHA/ACC 2017 + ISH 2020): (1) **Diagnosis confirmed**: ≥ 140/90 average × 3 visits over 1-4 wk (Stage 2 by 2017 guidelines = ≥ 130/80, but treatment thresholds vary); (2) **Lifestyle modification first** (foundation, may delay or prevent medication): - DASH diet (whole grains, fruits/veg, low-fat dairy, lean protein, low Na 1.5-2.3 g/d); - Weight loss 5-10% body weight (~ 1 mmHg per kg); - Exercise 150 min/wk moderate; - Alcohol limit (< 2 drinks/d men, < 1 women); - Smoking cessation; - Stress management; (3) **Medication initiation** if BP ≥ 140/90 with ASCVD risk factors or after 3-6 mo lifestyle insufficient: - **First-line** (per JNC 8 + AHA): - **ACEi/ARB** (lisinopril, losartan) — younger, DM, CKD, HF; - **CCB** (amlodipine) — older, Black; - **Thiazide diuretic** (chlorthalidone preferred, HCTZ); - **Combination** preferred over high-dose single (lower side effects, better adherence); - Avoid ACEi + ARB combination (no benefit, more side effects); (4) **Target BP**: < 130/80 most adults; < 140/90 some elderly; individualized based on comorbidity, frailty, life expectancy; SPRINT trial — intensive 120 better in selected; (5) **Follow-up**: monthly initially, then q3-6 mo when controlled; home BP monitoring; (6) **Workup secondary causes** if young, severe, refractory, suspicious: renal artery stenosis, primary aldosteronism, pheochromocytoma, Cushing''s, OSA; (7) **ASCVD risk assessment**: pooled cohort equations; if > 7.5% → statin discussion; (8) **Compliance + side effects**: address, simplify regimen, generic; (9) **Multidisciplinary**: PCP + cardiology + nephrology if complications; nutritionist; (10) **Patient education + self-management**"},{"label":"C","text":"Surgery"},{"label":"D","text":"Refuse care"},{"label":"E","text":"Hospice"}]'::jsonb,
  'B', 'HTN management: AHA/ACC 2017 + JNC 8 + ISH 2020. Lifestyle first. Medication based on comorbidity + age + race (ACEi/ARB, CCB, thiazide). Combination preferred. Target individualized < 130/80 (SPRINT) vs < 140/90. Secondary workup for suspicious. ASCVD risk assessment. Multidisciplinary primary care.', NULL,
  'easy', 'cardiovascular', 'review',
  'family_medicine', 'clinical_decision', 'cardiovascular', 'adult',
  'AHA/ACC 2017; JNC 8; ISH 2020', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'fammed_clinical_decision'
