select
  s.id, 'board', NULL, 'Community — health promotion + chronic disease prevention + reduce disparities through community-based + public health approach', '[{"label":"A","text":"Single clinic only"},{"label":"B","text":"Community-Oriented Primary Care (COPC): (1) **COPC principles**: integrate community + clinical perspectives, address health needs of defined population, multidisciplinary; (2) **5 steps**: define community + identify problems + research + intervene + evaluate; (3) **Community Health Needs Assessment**: data analysis + community input + health priorities; (4) **Population health management** including SDOH; (5) **Community-based interventions**: - School health programs; - Workplace health promotion; - Faith-based health partnerships; - Community health worker programs; - Public health collaboration (vaccination, screening); - Environmental + policy advocacy; (6) **Common community priorities**: chronic disease, mental health, substance use, violence, maternal + child, infectious disease, equity; (7) **Multisector partnerships**: healthcare + schools + employers + government + community organizations + faith + housing + food + transportation; (8) **Health Promotion**: education, social marketing, behavior change at population level; (9) **Health equity focus**: address disparities, structural racism, social determinants, marginalized populations; (10) **Disaster + pandemic preparedness + response**: community resilience; (11) **Quality improvement at community level**: data, evaluation, ongoing improvement; (12) **Modern**: integrated with primary care + value-based + population health + equity-focused"},{"label":"C","text":"Single specialty"},{"label":"D","text":"Random"},{"label":"E","text":"Refuse"}]'::jsonb,
  'B', 'Community-Oriented Primary Care: integration of community + clinical. CHNA. Community-based interventions. Multisector partnerships. Health equity focus. Disaster preparedness. Modern: integrated + value-based + equity-focused.', NULL,
  'easy', 'signs_symptoms', 'review',
