select
  s.id, 'board', NULL, 'Pediatric/Obstetric collaboration — reducing perinatal mortality + improving newborn outcomes', '[{"label":"A","text":"Pediatric + obstetric work separately"},{"label":"B","text":"Perinatal Care Integration — multidisciplinary obstetric + neonatal collaboration: (1) Pre-pregnancy: optimization (chronic disease, vaccinations, mental health, nutrition); (2) Antenatal: shared risk assessment, antenatal corticosteroid for preterm, MgSO4 for neuroprotection, GBS prophylaxis, level of care matching; (3) Intrapartum: skilled birth attendant, intermittent vs continuous monitoring, neonatal team alert for high-risk; (4) Delayed cord clamping 30-60 sec (improves iron stores, NEC, IVH); (5) Immediate skin-to-skin + early breastfeeding initiation; (6) Neonatal resuscitation if needed (NRP); (7) Newborn screening: pulse oximetry (CHD), hearing, blood spot (PKU, hypothyroid, CF, sickle cell, etc.), bilirubin; (8) NICU criteria + family involvement; (9) Postpartum: maternal screening (preeclampsia, depression, thyroid, infection, VTE, hemorrhage), breastfeeding support, contraception counseling; (10) Quality metrics: perinatal mortality rate, neonatal mortality, NICU admission, breastfeeding rates, preterm rate, c-section rate, severe morbidity; (11) Multidisciplinary team: obstetricians, midwives, neonatologists, anesthesia, lactation, social work, mental health, family medicine; (12) Continuity of care + transition"},{"label":"C","text":"Single specialty handles all"},{"label":"D","text":"Avoid newborn screening"},{"label":"E","text":"Discharge immediately"}]'::jsonb,
  'B', 'Perinatal care = integrative obstetric + neonatal + pediatric. Whole pregnancy journey + postpartum. Multidisciplinary team. Quality metrics. Outcomes improve with integrated care. Thai perinatal/neonatal mortality improving with system development. Family-centered. Continuous quality improvement.', NULL,
  'easy', 'obgyn', 'review',
  'ob_gyn', 'ems_mgmt', 'obgyn', 'adult',
  'WHO Standards for Improving Quality of Maternal and Newborn Care; ACOG/AAP Guidelines for Perinatal Care', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'obg_ems_mgmt'
  and s.audience = 'board'
  and not exists (
    select 1 from public.mcq_questions q
    where q.exam_source = 'AI-generated-board-seed'
