select
  s.id, 'board', NULL, 'Resident ถามเรื่อง pharmacology — pain management in orthopedic surgery', '[{"label":"A","text":"Opioid only"},{"label":"B","text":"Multimodal Pain Management — opioid-sparing approach: (1) **Multimodal**: target multiple pain pathways with lower doses of each agent — better analgesia + fewer side effects; (2) **Pre-op**: acetaminophen 1000 mg PO + gabapentin 300-600 mg PO + celecoxib 400 mg PO (selective COX-2 inhibitor — less GI/bleeding than non-selective); (3) **Intra-op**: regional anesthesia preferred (spinal, epidural, peripheral nerve block — femoral, adductor canal, popliteal); local infiltration analgesia (LIA — surgeon-administered bupivacaine/liposomal bupivacaine + adjuncts); (4) **Post-op**: scheduled acetaminophen + NSAID (caution renal, GI, bleeding) + low-dose opioid PRN; gabapentin/pregabalin if neuropathic component; ice + elevation; (5) **Avoid**: routine long-term opioids (epidemic + addiction), opioid only as primary analgesic, ketorolac > 5 days; (6) **Special populations**: elderly (reduce doses, avoid certain — Beers Criteria), CKD (NSAIDs avoid, acetaminophen OK), opioid-tolerant (multimodal + higher doses), addiction (consult addiction medicine); (7) **PCA (Patient-Controlled Analgesia)**: useful for major surgery; (8) **Continuous regional catheter**: extended block, less opioid, faster recovery; (9) **Discharge counseling**: limited opioid prescriptions, monitor for misuse, dispose unused, non-opioid alternatives; (10) **Pain assessment**: regular, multimodal scales (NRS, FLACC for pediatric, behavioral); (11) **Acute pain transition to chronic**: identify + intervene early, multidisciplinary pain management"},{"label":"C","text":"No pain management"},{"label":"D","text":"Long-term opioid for all"},{"label":"E","text":"Bedrest only"}]'::jsonb,
  'B', 'Multimodal pain management = standard. Opioid-sparing approach reduces side effects + addiction risk. Pre-op + intra-op + post-op planning. Regional anesthesia + LIA + scheduled non-opioids + minimal opioid PRN. Outcomes: better pain control + faster recovery + less opioid use. Special populations require adjustment. Address opioid epidemic.', NULL,
  'easy', 'procedures', 'review',
  'orthopedics', 'basic_science', 'procedures', 'adult',
  'AAOS Pain Management 2019; ASRA Guidelines on Acute Pain Management', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'ortho_basic_science'
  and s.audience = 'board'
