select
  s.id, 'board', NULL, 'Hospital implements fall prevention program for elderly + osteoporosis screening + treatment', '[{"label":"A","text":"No interventions needed"},{"label":"B","text":"Fracture Prevention Program — multilevel approach: (1) **Universal screening**: DXA at age 65 (women) + 70 (men), earlier if risk factors; FRAX score (10-year fracture risk); (2) **Fall prevention** (CDC STEADI): screen all elderly annually (3 Key Questions, Timed Up and Go), gait/balance, medication review (Beers), home safety, vision/hearing, vitamin D, exercise (Tai Chi, Otago); (3) **Treatment when indicated**: bisphosphonate (alendronate 70 mg/wk, risedronate, zoledronate 5 mg IV/year), denosumab (60 mg SC q6 mo — careful — discontinuation rebound fracture risk if not transitioned), teriparatide (20 mcg SC daily × 2 yr, anabolic for high-risk), romosozumab (anabolic 1 yr then anti-resorptive); Ca + vitamin D foundation; (4) **Secondary fracture prevention**: fragility fracture clinic — initiate Rx after any fragility fracture (50% reduction subsequent fractures with treatment); coordinator-based programs (Fracture Liaison Service) effective; (5) **Drug holiday** consideration with long-term bisphosphonate (5-10 yr — assess); (6) **Multidisciplinary**: PCP, orthopedic, endocrine, geriatric, PT, pharmacy; (7) **Patient education**: nutrition, exercise, fall prevention, medication adherence; (8) **Long-term**: regular DXA, adherence monitoring, side effect management (jaw osteonecrosis rare, atypical femur fracture rare with bisphosphonates); (9) **Quality metrics**: screening rate, treatment rate, fracture rate, mortality post-hip fracture (20-30% first year)"},{"label":"C","text":"Bed rest"},{"label":"D","text":"Aspirin only"},{"label":"E","text":"Avoid screening"}]'::jsonb,
  'B', 'Fracture prevention = multilevel + system approach. Universal screening (DXA, FRAX). Fall prevention (CDC STEADI). Anti-osteoporosis treatment when indicated. Secondary fracture prevention (FLS) — most underutilized opportunity. Multidisciplinary care. Modern: anabolic agents for very high risk + sequential therapy. Patient education + adherence. Mortality post-hip fracture significant.', NULL,
  'medium', 'msk_nontrauma', 'review',
  'orthopedics', 'ems_mgmt', 'msk_nontrauma', 'adult',
  'CDC STEADI; AACE 2020 Osteoporosis Guidelines; National Osteoporosis Foundation', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'ortho_ems_mgmt'
  and s.audience = 'board'
